/**
 * MedX datepicker forms runtime — runs on `npm run start` via medx-runtime-registry.cjs
 * Expiry and delivery date pickers.
 */
const DATEPICKER_TOKENS = Object.freeze({
  primary: { value: "forms-datepicker-primary", scope: "forms" },
  secondary: { value: "forms-datepicker-secondary", scope: "forms" },
  muted: { value: "forms-datepicker-muted", scope: "forms" },
  accent: { value: "forms-datepicker-accent", scope: "forms" },
  surface: { value: "forms-datepicker-surface", scope: "forms" },
});

const DATEPICKER_PRESETS = Object.freeze({
  default: { token: "primary", enabled: true, priority: 1 },
  compact: { token: "secondary", enabled: true, priority: 2 },
  emphasis: { token: "accent", enabled: true, priority: 3 },
  subtle: { token: "muted", enabled: true, priority: 4 },
});

const DATEPICKER_SUPPLY_CHAIN = Object.freeze({
  inventory: { label: "Inventory", key: "inventory", tier: "ops" },
  orders: { label: "Orders", key: "orders", tier: "ops" },
  compliance: { label: "Compliance", key: "compliance", tier: "regulatory" },
  coldChain: { label: "Cold chain", key: "cold-chain", tier: "ops" },
  blockchain: { label: "Blockchain", key: "blockchain", tier: "integrations" },
});

const datepickerRegistry = new Map();
const DATEPICKER_listeners = new Set();
let DATEPICKER_seq = 0;

function createDatepickerId(prefix = "medx-forms-datepicker") {
  DATEPICKER_seq += 1;
  return `${prefix}-${DATEPICKER_seq}`;
}

function registerDatepicker(config = {}) {
  const entryId = config.id ?? createDatepickerId();
  const preset = DATEPICKER_PRESETS[config.preset ?? "default"] ?? DATEPICKER_PRESETS.default;
  const token = DATEPICKER_TOKENS[config.token ?? preset.token] ?? DATEPICKER_TOKENS.primary;
  const entry = {
    id: entryId,
    preset: config.preset ?? "default",
    token,
    domain: config.domain ?? "inventory",
    domainMeta: DATEPICKER_SUPPLY_CHAIN[config.domain ?? "inventory"] ?? null,
    enabled: config.enabled ?? preset.enabled,
    priority: config.priority ?? preset.priority,
    metadata: config.metadata ?? {},
    createdAt: Date.now(),
    onChange: typeof config.onChange === "function" ? config.onChange : null,
  };
  datepickerRegistry.set(entryId, entry);
  notifyDatepickerListeners("register", entry);
  return entry;
}

function updateDatepicker(id, patch = {}) {
  const entry = datepickerRegistry.get(id);
  if (!entry) return null;
  Object.assign(entry, patch, { updatedAt: Date.now() });
  if (entry.onChange) entry.onChange(entry);
  notifyDatepickerListeners("update", entry);
  return entry;
}

function resolveDatepicker(id) {
  const entry = datepickerRegistry.get(id);
  if (!entry) return null;
  return {
    id: entry.id,
    token: entry.token.value,
    domain: entry.domain,
    enabled: entry.enabled,
    priority: entry.priority,
    label: entry.domainMeta?.label ?? entry.domain,
  };
}

function listDatepickerEntries(filter = {}) {
  let items = Array.from(datepickerRegistry.values());
  if (filter.domain) items = items.filter((e) => e.domain === filter.domain);
  if (filter.enabled != null) items = items.filter((e) => e.enabled === filter.enabled);
  return items.sort((a, b) => a.priority - b.priority);
}

function onDatepickerEvent(listener) {
  DATEPICKER_listeners.add(listener);
  return () => DATEPICKER_listeners.delete(listener);
}

function notifyDatepickerListeners(type, entry) {
  for (const listener of DATEPICKER_listeners) {
    try {
      listener({ type, entry, registrySize: datepickerRegistry.size });
    } catch (err) {
      console.warn("[medx:ui:forms:datepicker] listener error", err.message);
    }
  }
}

function getDatepickerMetrics() {
  const items = listDatepickerEntries();
  return {
    total: items.length,
    enabled: items.filter((e) => e.enabled).length,
    domains: [...new Set(items.map((e) => e.domain))],
    tokens: Object.keys(DATEPICKER_TOKENS).length,
    presets: Object.keys(DATEPICKER_PRESETS).length,
  };
}

async function runMedxDatepicker() {
  console.log("[medx:ui:forms:datepicker] runtime initialized");
  console.log(`[medx:ui:forms:datepicker] tokens=${Object.keys(DATEPICKER_TOKENS).length} presets=${Object.keys(DATEPICKER_PRESETS).length}`);

  const events = [];
  onDatepickerEvent((e) => events.push(e.type));

  const domains = Object.keys(DATEPICKER_SUPPLY_CHAIN);
  const presets = Object.keys(DATEPICKER_PRESETS);
  for (let i = 0; i < domains.length; i += 1) {
    registerDatepicker({
      domain: domains[i],
      preset: presets[i % presets.length],
      metadata: { seed: i, module: "forms/datepicker" },
    });
  }

  const first = listDatepickerEntries()[0];
  if (first) updateDatepicker(first.id, { priority: 0, metadata: { ...first.metadata, promoted: true } });

  const metrics = getDatepickerMetrics();
  const resolved = first ? resolveDatepicker(first.id) : null;

  console.log(`[medx:ui:forms:datepicker] registered=${metrics.total} enabled=${metrics.enabled}`);
  console.log(`[medx:ui:forms:datepicker] domains=${metrics.domains.join(",")}`);
  console.log(`[medx:ui:forms:datepicker] events=${events.join(",")}`);
  if (resolved) console.log(`[medx:ui:forms:datepicker] sample=${resolved.token}:${resolved.domain}`);
  console.log("[medx:ui:forms:datepicker] bootstrap complete");
}

module.exports = runMedxDatepicker;
